import { createClient } from '@/lib/supabase/server';
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from '@/components/ui/table';
import { Badge } from '@/components/ui/badge';

export default async function ClientsPage() {
  const supabase = await createClient();
  const { data: { user } } = await supabase.auth.getUser();
  const { data: merchant } = await supabase.from('merchants').select('id').eq('user_id', user!.id).single();

  const { data: cards } = await supabase
    .from('customer_cards')
    .select('*, customers(name, email), loyalty_programs!inner(name, type, merchant_id)')
    .eq('loyalty_programs.merchant_id', merchant!.id)
    .order('last_activity', { ascending: false });

  return (
    <div>
      <h2 className="text-2xl font-bold mb-6">Clients</h2>
      {!cards?.length ? (
        <p className="text-gray-500">No clients yet. Share your QR code to get started!</p>
      ) : (
        <Table>
          <TableHeader>
            <TableRow>
              <TableHead>Name</TableHead>
              <TableHead>Email</TableHead>
              <TableHead>Program</TableHead>
              <TableHead>Progress</TableHead>
              <TableHead>Tier</TableHead>
              <TableHead>Last Activity</TableHead>
            </TableRow>
          </TableHeader>
          <TableBody>
            {cards.map((card: any) => (
              <TableRow key={card.id}>
                <TableCell>{card.customers?.name || '—'}</TableCell>
                <TableCell>{card.customers?.email}</TableCell>
                <TableCell>{card.loyalty_programs?.name}</TableCell>
                <TableCell>
                  {card.loyalty_programs?.type === 'stamp'
                    ? `${card.current_stamps} stamps`
                    : `${card.current_points} pts`}
                </TableCell>
                <TableCell><Badge variant="outline" className="capitalize">{card.tier}</Badge></TableCell>
                <TableCell>{new Date(card.last_activity).toLocaleDateString()}</TableCell>
              </TableRow>
            ))}
          </TableBody>
        </Table>
      )}
    </div>
  );
}
```

