**TASK 18: Basic Campaign Send (Dashboard)**

Create `apps/dashboard/src/components/campaign-form.tsx`:
```typescript
'use client';
import { useState } from 'react';
import { useRouter } from 'next/navigation';
import { createClient } from '@/lib/supabase/client';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Textarea } from '@/components/ui/textarea';

export function CampaignForm({ merchantId }: { merchantId: string }) {
  const [title, setTitle] = useState('');
  const [body, setBody] = useState('');
  const [loading, setLoading] = useState(false);
  const router = useRouter();
  const supabase = createClient();

  async function handleSend(e: React.FormEvent) {
    e.preventDefault();
    setLoading(true);

    const { data: campaign, error } = await supabase.from('campaigns').insert({
      merchant_id: merchantId,
      title,
      body,
      type: 'push',
      target_segment: 'all',
      status: 'draft',
    }).select().single();

    if (error || !campaign) { setLoading(false); return; }

    await supabase.functions.invoke('send-push', { body: { campaign_id: campaign.id } });

    setTitle('');
    setBody('');
    setLoading(false);
    router.refresh();
  }

  return (
    <form onSubmit={handleSend} className="space-y-4 max-w-lg p-4 border rounded-lg">
      <h3 className="font-semibold">Send Push Notification</h3>
      <div><Label>Title</Label><Input value={title} onChange={(e) => setTitle(e.target.value)} placeholder="e.g. Weekend Special!" required /></div>
      <div><Label>Message</Label><Textarea value={body} onChange={(e) => setBody(e.target.value)} placeholder="e.g. 20% off all items this weekend!" required /></div>
      <Button type="submit" disabled={loading}>{loading ? 'Sending...' : 'Send to All Clients'}</Button>
    </form>
  );
}
```

